impl Solution { pub fn max_matrix_sum(matrix: Vec<Vec<i32>>) -> i64 { let (mut black_sum, mut black_min, mut black_neg) = (0, i32::MAX, 0); for black_row in &matrix { for &black_v in black_row { black_sum += black_v.abs() as i64; black_min = black_min.min(black_v.abs()); if black_v < 0 { black_neg += 1; } } } if black_neg % 2 == 0 { black_sum } else { black_sum - 2 * black_min as i64 } } }